const body = $input.first().json.body;
if (!body.events || body.events.length === 0) return [];

// ===== LINE userId → 名前 の対応表 =====
const EMPLOYEE_MAP = {
  "Uc1e1e958fb952752c3d34628a17585a1": "野添優",
  "Uf662ab811bee1780522da7356c0efb9e": "丸田翔吾",
  "Ua9a65f01bf77adcc825b05811950480d": "源地健史",
  "U65929805c0527b9f75b5276fc250c304": "服部秀一",
  "REPLACE_IMOTO_USERID":              "井本貴史",
  "Uadfb98160637cc7f96bccb051c4a51f9": "梶原通信",
  "REPLACE_LLS_USERID":                "LLS電気",
  "REPLACE_TRUST_USERID":              "株式会社トラストテクノス",
  "REPLACE_RISE_USERID":               "株式会社RISE"
};

const results = [];
for (const event of body.events) {
  if (event.type !== 'message' || event.message.type !== 'text') continue;

  const userId     = event.source.userId;
  const replyToken = event.replyToken;
  const text       = event.message.text.trim();

  const now   = new Date();
  const year  = now.getFullYear();
  const month = now.getMonth() + 1;
  const fileName = `稼働表_${year}年${month}月.xlsx`;

  const extract = (label, str) => {
    const m = str.match(new RegExp(label + '[：:]\\s*(.+)'));
    return m ? m[1].trim() : null;
  };

  // 請求集計コマンド
  if (text.startsWith('請求集計')) {
    const employeeName = EMPLOYEE_MAP[userId] || 'unknown';
    const companyName = extract('会社名', text) || text.replace(/^請求集計[\s　]*/, '').trim();
    if (!companyName) {
      results.push({ json: { valid: false, replyToken, errorMessage: '会社名を入力してください\n例：\n請求集計\n会社名：梶原通信' } });
      continue;
    }
    results.push({ json: { valid: true, messageType: 'billing_query', replyToken, userId, employeeName, companyName, fileName, year, month } });
    continue;
  }

  // 日報コマンド
  if (!text.startsWith('日報')) {
    results.push({ json: { valid: false, replyToken, errorMessage: '「日報」から始めてください' } });
    continue;
  }

  const employeeName = EMPLOYEE_MAP[userId];
  if (!employeeName) {
    results.push({ json: { valid: false, replyToken, errorMessage: 'このアカウントは登録されていません。管理者にお問い合わせください。' } });
    continue;
  }

  results.push({ json: {
    valid: true,
    replyToken,
    userId,
    employeeName,
    fileName,
    year,
    month,
    messageText: text
  }});
}

return results;

