const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('請求集計準備').first().json;
  const currentFI = $('請求集計ファイル情報取得（当月）').first().json;
  let prevFI = null;
  try { prevFI = $('請求集計ファイル情報取得（前月）').first().json; } catch(e) {}
  const MULTI = ['梶原通信','LLS電気','株式会社トラストテクノス','株式会社RISE'];
  const isMulti = MULTI.includes(data.companyName);
  const highwayCol = isMulti ? 12 : 10;
  const distanceCol = isMulti ? 13 : 11;
  let startDate, endDate;
  if (data.is20) {
    const pY = data.month === 1 ? data.year - 1 : data.year;
    const pM = data.month === 1 ? 12 : data.month - 1;
    startDate = new Date(Date.UTC(pY, pM - 1, 21));
    endDate = new Date(Date.UTC(data.year, data.month - 1, 20));
  } else {
    startDate = new Date(Date.UTC(data.year, data.month - 1, 1));
    endDate = new Date(Date.UTC(data.year, data.month, 0));
  }
  const records = {};
  const processWB = async (fi) => {
    if (!fi || !fi['@microsoft.graph.downloadUrl']) return;
    const res = await this.helpers.httpRequest({ method: 'GET', url: fi['@microsoft.graph.downloadUrl'], encoding: 'arraybuffer', returnFullResponse: false });
    const wb = new ExcelJS.Workbook();
    await wb.xlsx.load(Buffer.from(res), { useSharedStrings: false });
    wb.eachSheet((sheet) => {
      const empName = sheet.name;
      sheet.eachRow((row, num) => {
        if (num < 2) return;
        const dateCell = row.getCell(1).value;
        const company = row.getCell(3).value;
        if (!company || String(company).trim() !== data.companyName) return;
        if (!dateCell || typeof dateCell.getTime !== 'function') return;
        const d = new Date(dateCell.getTime() + 9 * 3600000);
        const dUTC = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
        if (dUTC < startDate || dUTC > endDate) return;
        const dateStr = `${d.getUTCMonth()+1}/${d.getUTCDate()}`;
        const shift = row.getCell(2).value || '';
        const site = row.getCell(4).value || '';
        const key = `${dUTC.getTime()}|${shift}|${site}`;
        const hw = row.getCell(highwayCol).value || 0;
        const dist = row.getCell(distanceCol).value || 0;
        if (!records[key]) records[key] = { dateStr, shift, site, employees: [], highway: 0, distance: 0, sortKey: dUTC.getTime() };
        if (!records[key].employees.includes(empName)) records[key].employees.push(empName);
        records[key].highway = Math.max(records[key].highway, hw);
        records[key].distance = Math.max(records[key].distance, dist);
      });
    });
  };
  await processWB(currentFI);
  if (data.is20 && prevFI) await processWB(prevFI);
  const sorted = Object.values(records).sort((a, b) => a.sortKey - b.sortKey);
  let totalHighway = 0, totalDistance = 0;
  const lines = sorted.map(r => {
    totalHighway += r.highway; totalDistance += r.distance;
    let line = `${r.dateStr}  ${r.shift}  ${r.site}  ${r.employees.join(' ')}`;
    if (r.highway > 0) line += `  高速:¥${r.highway.toLocaleString('ja-JP')}`;
    if (r.distance > 0) line += `  距離:${r.distance}km`;
    return line;
  });
  const sM = data.is20 ? (data.month === 1 ? 12 : data.month - 1) : data.month;
  const sD = data.is20 ? 21 : 1;
  const eM = data.is20 ? data.month : data.month;
  const eD = data.is20 ? 20 : new Date(data.year, data.month, 0).getDate();
  const period = `${sM}/${sD}〜${eM}/${eD}`;
  let msg = `【${data.companyName} 請求集計】
期間：${period}

`;
  if (lines.length === 0) { msg += '該当する稼働記録がありません'; }
  else {
    msg += lines.join('\n') + '\n\n────────────\n';
    msg += `稼働日数：${sorted.length}日`;
    if (totalHighway > 0) msg += `\n高速合計：¥${totalHighway.toLocaleString('ja-JP')}`;
    if (totalDistance > 0) msg += `\n距離合計：${totalDistance}km`;
  }
  const billingFileName = `請求集計_${data.year}年${String(data.month).padStart(2,'0')}月.xlsx`;
  return [{ json: { replyToken: data.replyToken, replyMessage: msg, records: sorted, companyName: data.companyName, billingFileName, year: data.year, month: data.month } }];
})();

