const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('請求集計処理').first().json;
  const fileInfo = $input.first().json;
  const wb = new ExcelJS.Workbook();
  // 既存ファイルがあれば読み込む
  if (fileInfo['@microsoft.graph.downloadUrl']) {
    try {
      const res = await this.helpers.httpRequest({ method: 'GET', url: fileInfo['@microsoft.graph.downloadUrl'], encoding: 'arraybuffer', returnFullResponse: false });
      await wb.xlsx.load(Buffer.from(res), { useSharedStrings: false });
    } catch(e) { /* 読み込み失敗時は新規作成 */ }
  }
  // シート取得または作成
  let sheet = wb.getWorksheet(data.companyName);
  if (sheet) {
    // シートをクリア（ヘッダー以外）
    const rows = [];
    sheet.eachRow((row, num) => { if (num >= 2) rows.push(num); });
    rows.reverse().forEach(num => sheet.spliceRows(num, 1));
  } else {
    sheet = wb.addWorksheet(data.companyName);
    // ヘッダー行
    const hdr = sheet.getRow(1);
    hdr.getCell(1).value = '日付';
    hdr.getCell(2).value = '区分';
    hdr.getCell(3).value = '現場名';
    hdr.getCell(4).value = '人員名';
    hdr.getCell(5).value = '高速(円)';
    hdr.getCell(6).value = '距離(km)';
    hdr.commit();
  }
  // データ書き込み
  let rowNum = 2;
  for (const rec of data.records) {
    const row = sheet.getRow(rowNum++);
    row.getCell(1).value = rec.dateStr;
    row.getCell(2).value = rec.shift;
    row.getCell(3).value = rec.site;
    row.getCell(4).value = rec.employees.join(' ');
    row.getCell(5).value = rec.highway || 0;
    row.getCell(6).value = rec.distance || 0;
    row.commit();
  }
  const buf = await wb.xlsx.writeBuffer({ useSharedStrings: false });
  const bin = await this.helpers.prepareBinaryData(Buffer.from(buf), data.billingFileName, 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
  return [{ json: { ...data }, binary: { data: bin } }];
})();
